import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Performance Management","description":"","frontmatter":{},"headers":[],"relativePath":"modules/performance.md","filePath":"modules/performance.md"}'),o={name:"modules/performance.md"};function i(n,e,l,d,c,h){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="performance-management" tabindex="-1">Performance Management <a class="header-anchor" href="#performance-management" aria-label="Permalink to &quot;Performance Management&quot;">​</a></h1><p>The Performance Management module enables structured, fair, and data-driven employee appraisals. It supports configurable review cycles where employees complete self-assessments, managers provide ratings, and HR finalises scores. The module includes comprehensive reporting on rating distributions and cycle summaries.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Navigate to <strong>HR Panel → Performance</strong> or <code>/performance</code>. The module consists of:</p><table tabindex="0"><thead><tr><th>Section</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td><strong>Appraisal Cycles</strong></td><td><code>/performance/cycles</code></td><td>Define review periods</td></tr><tr><td><strong>Rating Forms</strong></td><td><code>/performance/ratings</code></td><td>Individual employee assessments</td></tr><tr><td><strong>Reports</strong></td><td><code>/performance/reports</code></td><td>Analytics and distribution charts</td></tr></tbody></table><hr><h2 id="appraisal-cycles" tabindex="-1">Appraisal Cycles <a class="header-anchor" href="#appraisal-cycles" aria-label="Permalink to &quot;Appraisal Cycles&quot;">​</a></h2><p>An appraisal cycle defines a period during which employees are reviewed. You can run multiple cycles per year (e.g., mid-year and year-end) or a single annual review.</p><h3 id="creating-an-appraisal-cycle" tabindex="-1">Creating an Appraisal Cycle <a class="header-anchor" href="#creating-an-appraisal-cycle" aria-label="Permalink to &quot;Creating an Appraisal Cycle&quot;">​</a></h3><ol><li>Navigate to <strong>Performance → Appraisal Cycles</strong></li><li>Click <strong>New Cycle</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Cycle Name</strong></td><td>Yes</td><td>e.g., <code>Q2 2026 Review</code>, <code>Annual Appraisal 2026</code></td></tr><tr><td><strong>Start Date</strong></td><td>Yes</td><td>When the appraisal period begins (e.g., first day of Q2)</td></tr><tr><td><strong>End Date</strong></td><td>Yes</td><td>When the appraisal period ends</td></tr><tr><td><strong>Review Deadline</strong></td><td>Yes</td><td>Deadline for all assessments to be submitted</td></tr><tr><td><strong>Department</strong></td><td>No</td><td>Leave blank for company-wide; select for department-specific cycles</td></tr><tr><td><strong>Status</strong></td><td>Auto</td><td>Draft → Active → Completed</td></tr><tr><td><strong>Description</strong></td><td>No</td><td>Notes about the focus areas of this cycle</td></tr></tbody></table><ol start="4"><li>Click <strong>Save</strong></li></ol><h3 id="cycle-status-flow" tabindex="-1">Cycle Status Flow <a class="header-anchor" href="#cycle-status-flow" aria-label="Permalink to &quot;Cycle Status Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Draft → Active → Completed</span></span></code></pre></div><ul><li><strong>Draft</strong> — Cycle is being set up; no assessments visible to employees yet</li><li><strong>Active</strong> — Self-assessments and manager reviews are open</li><li><strong>Completed</strong> — Ratings finalised; cycle is locked and read-only</li></ul><p>To move a cycle from Draft to Active, click <strong>Activate Cycle</strong>. This makes the assessment forms visible to all employees in scope.</p><hr><h2 id="assessment-forms" tabindex="-1">Assessment Forms <a class="header-anchor" href="#assessment-forms" aria-label="Permalink to &quot;Assessment Forms&quot;">​</a></h2><p>When a cycle is Active, every in-scope employee has a rating form generated for them.</p><h3 id="form-structure" tabindex="-1">Form Structure <a class="header-anchor" href="#form-structure" aria-label="Permalink to &quot;Form Structure&quot;">​</a></h3><p>Each rating form contains the following sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>Completed By</th><th>Description</th></tr></thead><tbody><tr><td><strong>Self-Assessment</strong></td><td>Employee</td><td>Employee rates themselves across all criteria</td></tr><tr><td><strong>Manager Review</strong></td><td>Reporting Manager</td><td>Manager rates the employee</td></tr><tr><td><strong>Final Score</strong></td><td>HR / Admin</td><td>Weighted composite score calculated by the system</td></tr></tbody></table><h3 id="rating-criteria" tabindex="-1">Rating Criteria <a class="header-anchor" href="#rating-criteria" aria-label="Permalink to &quot;Rating Criteria&quot;">​</a></h3><p>Default rating criteria (configurable per cycle):</p><table tabindex="0"><thead><tr><th>Criterion</th><th>Description</th></tr></thead><tbody><tr><td><strong>Work Quality</strong></td><td>Accuracy and thoroughness of work output</td></tr><tr><td><strong>Productivity</strong></td><td>Volume and efficiency of work completed</td></tr><tr><td><strong>Communication</strong></td><td>Verbal and written communication skills</td></tr><tr><td><strong>Teamwork</strong></td><td>Collaboration with colleagues</td></tr><tr><td><strong>Problem Solving</strong></td><td>Ability to identify and resolve issues</td></tr><tr><td><strong>Leadership</strong></td><td>(Manager-level employees) Team management effectiveness</td></tr><tr><td><strong>Goal Achievement</strong></td><td>Progress against goals set in the previous cycle</td></tr></tbody></table><h3 id="scoring-scale" tabindex="-1">Scoring Scale <a class="header-anchor" href="#scoring-scale" aria-label="Permalink to &quot;Scoring Scale&quot;">​</a></h3><p>Each criterion is scored on a 1–5 scale:</p><table tabindex="0"><thead><tr><th>Score</th><th>Label</th></tr></thead><tbody><tr><td>5</td><td>Outstanding</td></tr><tr><td>4</td><td>Excellent</td></tr><tr><td>3</td><td>Good</td></tr><tr><td>2</td><td>Average</td></tr><tr><td>1</td><td>Poor</td></tr></tbody></table><hr><h2 id="self-assessment-process" tabindex="-1">Self-Assessment Process <a class="header-anchor" href="#self-assessment-process" aria-label="Permalink to &quot;Self-Assessment Process&quot;">​</a></h2><h3 id="employee-steps" tabindex="-1">Employee Steps <a class="header-anchor" href="#employee-steps" aria-label="Permalink to &quot;Employee Steps&quot;">​</a></h3><ol><li>Log in and navigate to <strong>My Performance</strong></li><li>The active cycle assessment form is displayed</li><li>Rate yourself on each criterion (1–5)</li><li>Add comments for each criterion (optional but encouraged)</li><li>Write an overall self-summary in the text box</li><li>Click <strong>Submit Self-Assessment</strong></li></ol><p>Once submitted, the self-assessment is locked and the manager is notified to complete their review.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Employees can save their progress as a draft before final submission. Use the <strong>Save Draft</strong> button to preserve ratings without locking the form.</p></div><hr><h2 id="manager-review-process" tabindex="-1">Manager Review Process <a class="header-anchor" href="#manager-review-process" aria-label="Permalink to &quot;Manager Review Process&quot;">​</a></h2><h3 id="manager-steps" tabindex="-1">Manager Steps <a class="header-anchor" href="#manager-steps" aria-label="Permalink to &quot;Manager Steps&quot;">​</a></h3><ol><li>Navigate to <strong>Performance → My Team Reviews</strong></li><li>Click on an employee&#39;s pending review</li><li>The form shows the employee&#39;s self-assessment scores for reference</li><li>Enter your own rating (1–5) for each criterion</li><li>Add comments explaining your rating</li><li>Write an overall manager summary</li><li>Click <strong>Submit Manager Review</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">Calibration</p><p>Managers can see all their direct reports&#39; self-scores before entering their own ratings. This helps with calibration across the team. However, manager scores are independent — the manager&#39;s score is not locked to match the employee&#39;s self-score.</p></div><hr><h2 id="final-score-calculation" tabindex="-1">Final Score Calculation <a class="header-anchor" href="#final-score-calculation" aria-label="Permalink to &quot;Final Score Calculation&quot;">​</a></h2><p>Once both self-assessment and manager review are submitted, the system calculates the final weighted score:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Final Score = (Self Score × 0.4) + (Manager Score × 0.6)</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Configurable Weights</p><p>The weighting can be adjusted in <strong>Settings → Performance</strong>. Default is 40% employee / 60% manager.</p></div><h3 id="rating-labels" tabindex="-1">Rating Labels <a class="header-anchor" href="#rating-labels" aria-label="Permalink to &quot;Rating Labels&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Score Range</th><th>Label</th><th>Description</th></tr></thead><tbody><tr><td>4.5 – 5.0</td><td><strong>Outstanding</strong></td><td>Consistently exceeds all expectations</td></tr><tr><td>3.5 – 4.4</td><td><strong>Excellent</strong></td><td>Regularly exceeds expectations</td></tr><tr><td>2.5 – 3.4</td><td><strong>Good</strong></td><td>Meets expectations</td></tr><tr><td>1.5 – 2.4</td><td><strong>Average</strong></td><td>Partially meets expectations</td></tr><tr><td>1.0 – 1.4</td><td><strong>Poor</strong></td><td>Does not meet expectations</td></tr></tbody></table><hr><h2 id="finalising-ratings" tabindex="-1">Finalising Ratings <a class="header-anchor" href="#finalising-ratings" aria-label="Permalink to &quot;Finalising Ratings&quot;">​</a></h2><p>After all reviews in a cycle are submitted, HR or Admin finalises the cycle.</p><ol><li>Navigate to <strong>Performance → Appraisal Cycles</strong></li><li>Click the active cycle</li><li>Review the summary table: pending count, submitted count, average scores</li><li>For any employees where both assessments are not yet submitted, you can: <ul><li>Send a reminder email</li><li>Manually mark the form as complete (with a note)</li></ul></li><li>Click <strong>Finalise Cycle</strong></li><li>Confirm in the dialog</li><li>Cycle status changes to <strong>Completed</strong></li></ol><p>Once finalised:</p><ul><li>All forms are locked and read-only</li><li>Scores are recorded in the employee&#39;s performance history</li><li>Performance reports are updated with the cycle data</li></ul><hr><h2 id="performance-reports" tabindex="-1">Performance Reports <a class="header-anchor" href="#performance-reports" aria-label="Permalink to &quot;Performance Reports&quot;">​</a></h2><p>Navigate to <strong>Reports → Performance</strong> to access:</p><h3 id="rating-distribution-chart" tabindex="-1">Rating Distribution Chart <a class="header-anchor" href="#rating-distribution-chart" aria-label="Permalink to &quot;Rating Distribution Chart&quot;">​</a></h3><p>A bar or pie chart showing how many employees received each rating label:</p><ul><li>Outstanding</li><li>Excellent</li><li>Good</li><li>Average</li><li>Poor</li></ul><p>Useful for identifying whether performance is normally distributed or skewed.</p><h3 id="cycle-summary-table" tabindex="-1">Cycle Summary Table <a class="header-anchor" href="#cycle-summary-table" aria-label="Permalink to &quot;Cycle Summary Table&quot;">​</a></h3><p>For each completed cycle:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Cycle Name</td><td>Name and period</td></tr><tr><td>Total Assessed</td><td>Number of employees included</td></tr><tr><td>Average Score</td><td>Mean final score</td></tr><tr><td>Highest Score</td><td>Top performer score</td></tr><tr><td>Lowest Score</td><td>Lowest score in cycle</td></tr><tr><td>Outstanding Count</td><td>Employees with Outstanding rating</td></tr><tr><td>Poor Count</td><td>Employees with Poor rating</td></tr></tbody></table><h3 id="department-comparison" tabindex="-1">Department Comparison <a class="header-anchor" href="#department-comparison" aria-label="Permalink to &quot;Department Comparison&quot;">​</a></h3><p>Compare average scores across departments in the same cycle. Useful for identifying high-performing and under-performing teams.</p><h3 id="individual-history" tabindex="-1">Individual History <a class="header-anchor" href="#individual-history" aria-label="Permalink to &quot;Individual History&quot;">​</a></h3><p>View any employee&#39;s performance history across all cycles: their self-scores, manager scores, and final ratings with trend lines.</p>',67)])])}const g=t(o,[["render",i]]);export{p as __pageData,g as default};
